/** Initializes the offline ontology graph and its keyboard-accessible controls. */
function initializeReport(): void {
  const ontology = readOntology();
  const container = requireElement<HTMLElement>("ontology-graph");
  const state: GraphState = {
    ontology,
    search: requireElement<HTMLInputElement>("graph-search"),
    support: requireElement<HTMLInputElement>("support-filter"),
    supportValue: requireElement<HTMLElement>("support-value"),
    relations: requireElement<HTMLInputElement>("relation-filter"),
    status: requireElement<HTMLElement>("graph-status"),
    details: requireElement<HTMLElement>("graph-details"),
    cy: cytoscape({
      container,
      elements: toElements(ontology.types),
      style: graphStyles,
      layout: {
        name: "cose",
        animate: false,
        randomize: false,
        nodeRepulsion: () => 9_000,
        idealEdgeLength: () => 130,
      },
      minZoom: 0.25,
      maxZoom: 2.5,
      wheelSensitivity: 0.2,
    }),
  };

  state.cy.on("tap", "node, edge", (event) => showDetails(state, event.target.id()));
  state.search.addEventListener("input", () => applyFilters(state));
  state.support.addEventListener("input", () => applyFilters(state));
  state.relations.addEventListener("change", () => applyFilters(state));
  requireElement<HTMLButtonElement>("fit-graph").addEventListener("click", () => {
    state.cy.fit(undefined, 48);
  });
  requireElement<HTMLButtonElement>("reset-graph").addEventListener("click", () => {
    state.search.value = "";
    state.support.value = "1";
    state.relations.checked = true;
    applyFilters(state);
    state.cy.fit(undefined, 48);
  });
  applyFilters(state);
}

