/** Converts canonical nodes, relation types, and is-a links to Cytoscape elements. */
function toElements(types: CanonicalType[]): ElementDefinition[] {
  const nodes = types
    .filter(({ kind }) => kind === "NodeType")
    .map((type) => ({
      data: {
        id: type.id,
        label: type.label,
        definition: type.definition,
        support: type.supportCount,
        aliases: type.aliases.join(", "),
        kind: type.kind,
      },
    }));
  const relationEdges = types
    .filter((type) => type.kind === "RelType" && type.domain !== undefined && type.range !== undefined)
    .map((type) => ({
      data: {
        id: type.id,
        source: type.domain,
        target: type.range,
        label: type.label,
        definition: type.definition,
        support: type.supportCount,
        kind: type.kind,
      },
    }));
  const subtypeEdges = types
    .filter((type) => type.kind === "NodeType" && type.parent !== undefined)
    .map((type) => ({
      data: {
        id: `parent-${type.id}`,
        source: type.id,
        target: type.parent,
        label: "is-a",
        definition: `${type.label} is a subtype`,
        support: type.supportCount,
        kind: "Subtype",
        subtype: true,
      },
    }));
  return [...nodes, ...relationEdges, ...subtypeEdges];
}

/** Applies all filters together and announces the visible graph size. */
function applyFilters(state: GraphState): void {
  const query = state.search.value.trim().toLocaleLowerCase("en");
  const minimumSupport = Number(state.support.value);
  state.supportValue.textContent = String(minimumSupport);
  state.cy.batch(() => {
    state.cy.elements().removeClass("filtered");
    state.cy.nodes().forEach((node) => {
      const label = String(node.data("label")).toLocaleLowerCase("en");
      const aliases = String(node.data("aliases") ?? "").toLocaleLowerCase("en");
      const visible = Number(node.data("support")) >= minimumSupport
        && (query.length === 0 || label.includes(query) || aliases.includes(query));
      if (!visible) {
        node.addClass("filtered");
        node.connectedEdges().addClass("filtered");
      }
    });
    if (!state.relations.checked) {
      state.cy.edges('[kind = "RelType"]').addClass("filtered");
    }
  });
  const visibleNodes = state.cy.nodes().not(".filtered").length;
  const visibleEdges = state.cy.edges().not(".filtered").length;
  state.status.textContent = `${visibleNodes} types and ${visibleEdges} relations visible`;
}

/** Shows escaped data already rendered by textContent in the details region. */
function showDetails(state: GraphState, elementId: string): void {
  const element = state.cy.getElementById(elementId);
  const label = String(element.data("label") ?? "Unknown");
  const definition = String(element.data("definition") ?? "No definition available.");
  const support = String(element.data("support") ?? "0");
  state.details.replaceChildren(
    createTextElement("h3", label),
    createTextElement("p", definition),
    createTextElement("p", `Support: ${support}`),
  );
}

/** Reads the safely serialized ontology payload from the report document. */
function readOntology(): Ontology {
  const payload = requireElement<HTMLScriptElement>("ontology-data").textContent;
  if (payload === null) {
    throw new Error("Ontology report data is missing");
  }
  return JSON.parse(payload) as Ontology;
}

/** Returns an element by id or fails with a useful initialization error. */
function requireElement<ElementType extends HTMLElement>(id: string): ElementType {
  const element = document.getElementById(id);
  if (element === null) {
    throw new Error(`Report element not found: ${id}`);
  }
  return element as ElementType;
}

/** Creates a text-only element so graph data never becomes markup. */
function createTextElement(tagName: "h3" | "p", text: string): HTMLElement {
  const element = document.createElement(tagName);
  element.textContent = text;
  return element;
}

